INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('gsph_state2_field_point_and_r_vector_tip_desync', 'STATE_2 field-point P marker and the r radius-vector tip render at different places → two conflicting "P"s on screen', 'MAJOR', 'peter_parker:renderer_primitives', 'show_field_point places the P marker at one location (a dim ball off to the upper-left) while show_radius_vectors draws the r radius-vector with its tip elsewhere (a separate white point lower-right); both read as "P". The field point P IS the r-vector tip at distance r, but the two are positioned independently, so the teacher sees a low-colour P and a separate white P and cannot tell which is the field point (founder asked on the recording: "the low-colour point P, or the white one — which do we need?").', 'In gauss_law_sphere STATE_2 anchor the field-point P marker exactly on the tip of the r radius-vector (identical world position) so there is a SINGLE P, labelled once; the field point and the r-vector tip must always coincide. Never render two markers that both read as P.', 'manual', 'STATE_2: exactly one point P on screen, sitting on the tip of the r reference line at distance r from the centre; no second P marker anywhere else.', 'FIXED', ARRAY['gauss_law_sphere'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_gauss_sphere_phet_review', 'incident'),
('gsph_state4_point_charge_invisible_sparse_canvas', 'STATE_4 point-charge half is a near-invisible tiny dot (no visible q sphere/label); canvas reads near-empty (Rule 19/24)', 'MAJOR', 'peter_parker:renderer_primitives', 'In compare_mode STATE_4 the lone point charge renders as a tiny dim dot with no charge-sphere body and no q label, and the shell half does not appear until shell_appears_at_ms=17000. For the opening ~17s the screen shows only a tiny dot plus (late) one field arrow — fewer than 3 legible primitives and no readable picture with sound off.', 'Render the STATE_4 point charge as a clearly visible labelled q sphere (sized like the other diamonds'' charges) with its radial field arrows, so the "simple case alone" beat is already a complete readable picture before the shell fades in.', 'manual', 'STATE_4 opening frame: a clearly visible labelled point charge q with radial field arrows reads as a complete picture; not a near-empty canvas with a single tiny dot.', 'FIXED', ARRAY['gauss_law_sphere'], ARRAY['src/lib/renderers/field_3d_renderer.ts', 'src/data/concepts/gauss_law_sphere.json'], 'session_2026-06-26_gauss_sphere_phet_review', 'incident'),
('gsph_state4_field_point_diagonal_not_horizontal', 'STATE_4 point-charge field point P + E-arrow read diagonal (up-left), not horizontal to the right of q (standard diagram)', 'MAJOR', 'peter_parker:renderer_primitives', 'Under the STATE_4 compare camera [0,1.9,12] the point-charge field point and its E-arrow point diagonally up-left instead of horizontally outward to the right of q. Same failure class as the fixed field3d_position_vector_foreshortened_3q_camera, recurring in the compare/point-charge layout. Founder explicitly asked: "make a horizontal point P, not this — only for the point charge."', 'Place the STATE_4 point-charge field point P horizontally to the right of q and billboard the E-arrow to camera-right (screen-horizontal) so it reads as the standard textbook point-charge diagram, never a diagonal into the camera.', 'manual', 'STATE_4: the point-charge field point P sits horizontally to the right of q and the E-arrow reads horizontal on screen at every camera used.', 'FIXED', ARRAY['gauss_law_sphere'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_gauss_sphere_phet_review', 'incident'),
('gsph_state4_compare_backloaded_long_empty_wait', 'STATE_4 back-loaded: ~17s sparse point-charge-only wait before the shell appears (shell_appears_at_ms 17000 in a 30s state)', 'MODERATE', 'alex:json_author', 'shell_appears_at_ms=17000 and compare_highlight_at_ms=26000 in a 30s STATE_4 leave the student on the sparse point-charge half alone for ~17s. The concrete-first staging (teach_concrete_before_abstract_compare) is correct, but the alone beat is mis-tuned — too long and too sparse.', 'Tighten STATE_4 pacing: make the point-charge-alone beat a complete readable picture (see gsph_state4_point_charge_invisible_sparse_canvas) and bring the shell + compare-highlight in sooner so no beat is a long near-empty wait.', 'manual', 'STATE_4: no beat longer than a few seconds shows a near-empty canvas; the alone → compare → formulas-match sequence flows without a long dead wait.', 'FIXED', ARRAY['gauss_law_sphere'], ARRAY['src/data/concepts/gauss_law_sphere.json'], 'session_2026-06-26_gauss_sphere_phet_review', 'incident'),
('teach_field3d_explore_grab_and_move_field_point', 'field_3d explore should let the teacher GRAB the field point (and charge) with the mouse and move it anywhere — E-arrow rotates to stay radial and rescales as 1/r² live (PhET-style)', 'MAJOR', 'alex:architect', 'Founder (2026-06-26 recording): the current explore is a radius SLIDER (STATE_7 r_gauss) plus camera-orbit drag only; mousedown only orbits the camera — there is no direct mouse-grab of the field point or the charge. The teacher wants to grab the test point and move it here and there like a PhET sim, watch the field DIRECTION change and the INTENSITY fall with distance, and see the intensity is the same all around a circle of fixed r.', 'Spec a draggable field-point "sensor" handle (and optionally a draggable charge) as a REUSABLE field_3d primitive on a fixed drag-plane through the centre: on drag, the verified engine recomputes r and r̂ and redraws the E-arrow (length ∝ kq/r², direction radial) + the live readout. Author it as DATA per Rule 27/28 (stable explorer id + a generic "move object" verb), never per-sim physics; add an idle auto-sweep so THE EYE can gate the interactive state. Once built, every field_3d diamond inherits the same grab-and-move test point.', 'manual', 'Architect/renderer: the explore state lets you drag the field point anywhere on the plane; the E-arrow stays radial, rescales as 1/r², reads equal magnitude around a circle of fixed r; physics computed by the engine, not authored per frame.', 'OPEN', ARRAY['gauss_law_sphere'], ARRAY['src/lib/renderers/field_3d_renderer.ts', 'src/data/concepts/gauss_law_sphere.json'], 'session_2026-06-26_gauss_sphere_phet_review', 'directive')
ON CONFLICT (bug_class) DO NOTHING;
